import React, { useState } from "react";
import {
  Container,
  Paper,
  Typography,
  TextField,
  Button,
  Alert,
  CircularProgress,
  Box,
} from "@mui/material";
import { useNavigate } from "react-router-dom";
import { sendOtp, verifyOtp, getRiderStatus } from "../services/api";

export default function RiderLogin() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [loading, setLoading] = useState(false);
  const [otpSent, setOtpSent] = useState(false);
  const [error, setError] = useState("");
  const [success, setSuccess] = useState("");

  // ✅ Send OTP only if rider is approved
  const handleSendOtp = async () => {
    if (!/^[6-9]\d{9}$/.test(mobile)) {
      setError("Mobile number must start with 6/7/8/9 and be 10 digits long.");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      // 1️⃣ Check rider approval status
      const statusRes = await getRiderStatus(); // token attached via axios interceptor
      const rider = statusRes.data?.data?.find((r) => r.mobile === mobile);
      if (!rider) {
        setError("Rider not found. Please register first.");
        setLoading(false);
        return;
      }
      if (rider.status !== "approved") {
        setError("Your account is not approved yet by admin.");
        setLoading(false);
        return;
      }

      // 2️⃣ Send OTP
      const res = await sendOtp(mobile, "rider");
      if (res.data?.success) {
        setOtpSent(true);
        setSuccess("OTP sent successfully!");
      } else {
        setError(res.data?.message || "Failed to send OTP");
      }
    } catch (err) {
      console.error("Send OTP error:", err);
      setError(err.response?.data?.message || "Server error. Try again later.");
    } finally {
      setLoading(false);
    }
  };

  // ✅ Verify OTP
  const handleVerifyOtp = async () => {
    if (otp.length !== 6) {
      setError("Enter a valid 6-digit OTP.");
      return;
    }

    setLoading(true);
    setError("");
    setSuccess("");

    try {
      const res = await verifyOtp(mobile, otp, "rider");
      if (res.data?.success) {
        const { token, role } = res.data.data;
        localStorage.setItem("token", token);
        localStorage.setItem("role", role);
        navigate("/rider-dashboard");
      } else {
        setError(res.data?.message || "OTP verification failed.");
      }
    } catch (err) {
      console.error("Verify OTP error:", err);
      setError(err.response?.data?.message || "Server error. Try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="xs">
      <Paper sx={{ mt: 6, p: 4, borderRadius: 3, textAlign: "center", boxShadow: 5 }}>
        <Typography variant="h4" sx={{ fontWeight: "bold", mb: 2 }}>
          Rider Login
        </Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}
        {success && <Alert severity="success" sx={{ mb: 2 }}>{success}</Alert>}

        <TextField
          fullWidth
          label="Mobile Number"
          value={mobile}
          onChange={(e) => setMobile(e.target.value)}
          margin="normal"
          inputProps={{ maxLength: 10, pattern: "^[6-9][0-9]{9}$" }}
          disabled={otpSent}
        />

        {otpSent && (
          <TextField
            fullWidth
            label="OTP"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            margin="normal"
            inputProps={{ maxLength: 6 }}
          />
        )}

        <Box sx={{ mt: 2 }}>
          {!otpSent ? (
            <Button
              fullWidth
              variant="contained"
              onClick={handleSendOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Send OTP"}
            </Button>
          ) : (
            <Button
              fullWidth
              variant="contained"
              onClick={handleVerifyOtp}
              disabled={loading}
            >
              {loading ? <CircularProgress size={24} color="inherit" /> : "Verify OTP"}
            </Button>
          )}
        </Box>

        <Typography sx={{ mt: 3 }}>
          Don’t have a rider account?{" "}
          <Button onClick={() => navigate("/rider-register")} sx={{ fontWeight: "bold" }}>
            Signup
          </Button>
        </Typography>

        <Typography sx={{ mt: 1 }}>
          Are you a User?{" "}
          <Button onClick={() => navigate("/login")} sx={{ fontWeight: "bold" }}>
            Login as User
          </Button>
        </Typography>
      </Paper>
    </Container>
  );
}
